mapper.select:
SELECT b.book_id, b.book_title, b.cover_image, b.author_name, b.book_price, COALESCE(r.avgRating, 0) AS avgRating FROM book b
LEFT JOIN ( SELECT book_id, AVG(review_score) AS avgRating FROM review GROUP BY book_id ) r ON b.book_id = r.book_id ORDER BY b.created_at DESC
LIMIT #{limit}

SELECT b.book_id, b.book_title, b.cover_image, b.author_name, b.book_price, COALESCE(s.totalSales, 0) AS totalSales FROM book b
LEFT JOIN ( SELECT book_id, SUM(quantity) AS totalSales FROM orderitem GROUP BY book_id ) s ON b.book_id = s.book_id
LIMIT #{limit}
